import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import NotFound from "@/pages/not-found";
import Dashboard from "@/pages/dashboard";
import Assessment from "@/pages/assessment";
import AlertsPage from "@/pages/alerts";
import Analytics from "@/pages/analytics";
import MapView from "@/pages/map-view";
import Layout from "@/components/layout";

function Router() {
  return (
    <Layout>
      <Switch>
        <Route path="/" component={Dashboard} />
        <Route path="/assessment" component={Assessment} />
        <Route path="/alerts" component={AlertsPage} />
        <Route path="/analytics" component={Analytics} />
        <Route path="/map" component={MapView} />
        <Route component={NotFound} />
      </Switch>
    </Layout>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <Toaster />
        <Router />
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

import { useState } from "react";
import { Link, useLocation } from "wouter";
import {
  LayoutDashboard,
  ScanSearch,
  Bell,
  BarChart3,
  Map,
  Menu,
  X,
  Satellite,
  AlertTriangle,
  Activity,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useQuery } from "@tanstack/react-query";

const navItems = [
  { href: "/", label: "Dashboard", icon: LayoutDashboard },
  { href: "/assessment", label: "Damage Assessment", icon: ScanSearch },
  { href: "/alerts", label: "Alerts", icon: Bell },
  { href: "/analytics", label: "Analytics", icon: BarChart3 },
  { href: "/map", label: "Map View", icon: Map },
];

export default function Layout({ children }: { children: React.ReactNode }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [location] = useLocation();

  const { data: stats } = useQuery<{ activeAlerts: number }>({
    queryKey: ["/api/stats"],
  });

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col">
      {/* Top App Bar */}
      <header className="fixed top-0 left-0 right-0 z-50 h-16 bg-slate-900 border-b border-slate-700 flex items-center px-4 gap-4 shadow-lg">
        <button
          className="lg:hidden p-2 rounded-md hover:bg-slate-700 transition-colors"
          onClick={() => setSidebarOpen(!sidebarOpen)}
        >
          {sidebarOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
        </button>

        <div className="flex items-center gap-3">
          <div className="flex items-center justify-center w-9 h-9 rounded-lg bg-blue-600">
            <Satellite className="h-5 w-5 text-white" />
          </div>
          <div className="hidden sm:block">
            <div className="font-bold text-white text-sm leading-tight">AI-LiDAR</div>
            <div className="text-xs text-slate-400 leading-tight">Disaster Assessment</div>
          </div>
        </div>

        <div className="flex-1" />

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-green-500/10 border border-green-500/20">
            <Activity className="h-3.5 w-3.5 text-green-400" />
            <span className="text-xs font-medium text-green-400">System Online</span>
          </div>

          {stats?.activeAlerts !== undefined && stats.activeAlerts > 0 && (
            <Link href="/alerts">
              <div className="relative p-2 rounded-md hover:bg-slate-700 cursor-pointer transition-colors">
                <Bell className="h-5 w-5 text-slate-300" />
                <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] flex items-center justify-center bg-red-500 rounded-full text-[10px] font-bold text-white px-1">
                  {stats.activeAlerts}
                </span>
              </div>
            </Link>
          )}

          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-xs font-bold text-white">
              OP
            </div>
            <span className="hidden md:block text-sm text-slate-300">Operator</span>
          </div>
        </div>
      </header>

      <div className="flex flex-1 pt-16">
        {/* Sidebar overlay (mobile) */}
        {sidebarOpen && (
          <div
            className="fixed inset-0 z-30 bg-black/60 lg:hidden"
            onClick={() => setSidebarOpen(false)}
          />
        )}

        {/* Sidebar */}
        <aside
          className={cn(
            "fixed top-16 left-0 bottom-0 z-40 w-64 bg-slate-900 border-r border-slate-700 flex flex-col transition-transform duration-200 lg:translate-x-0",
            sidebarOpen ? "translate-x-0" : "-translate-x-full"
          )}
        >
          <nav className="flex-1 p-4 space-y-1">
            {navItems.map(({ href, label, icon: Icon }) => {
              const active = location === href;
              return (
                <Link key={href} href={href}>
                  <div
                    className={cn(
                      "flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors cursor-pointer",
                      active
                        ? "bg-blue-600 text-white"
                        : "text-slate-400 hover:text-slate-100 hover:bg-slate-800"
                    )}
                    onClick={() => setSidebarOpen(false)}
                  >
                    <Icon className="h-4.5 w-4.5 flex-shrink-0" />
                    {label}
                    {label === "Alerts" && stats?.activeAlerts !== undefined && stats.activeAlerts > 0 && (
                      <span className="ml-auto min-w-[20px] h-5 flex items-center justify-center bg-red-500 rounded-full text-[10px] font-bold text-white px-1">
                        {stats.activeAlerts}
                      </span>
                    )}
                  </div>
                </Link>
              );
            })}
          </nav>

          <div className="p-4 border-t border-slate-700">
            <div className="flex items-center gap-2 px-3 py-2 rounded-lg bg-amber-500/10 border border-amber-500/20">
              <AlertTriangle className="h-4 w-4 text-amber-400 flex-shrink-0" />
              <div>
                <div className="text-xs font-semibold text-amber-300">Research Mode</div>
                <div className="text-[10px] text-amber-400/70">Simulated LiDAR data</div>
              </div>
            </div>
          </div>
        </aside>

        {/* Main content */}
        <main className="flex-1 lg:ml-64 min-h-screen">
          {children}
        </main>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { useToast } from "@/hooks/use-toast";
import {
  ScanSearch, Cpu, Layers, CheckCircle2, Clock, AlertTriangle,
  Zap, RefreshCw, Filter, MapPin
} from "lucide-react";
import type { DamageAssessment } from "@shared/schema";

const severityColor = {
  low: "bg-green-500/20 text-green-300 border-green-500/30",
  moderate: "bg-amber-500/20 text-amber-300 border-amber-500/30",
  severe: "bg-red-500/20 text-red-300 border-red-500/30",
};

const statusColor = {
  active: "bg-blue-500/20 text-blue-300 border-blue-500/30",
  pending: "bg-yellow-500/20 text-yellow-300 border-yellow-500/30",
  resolved: "bg-slate-500/20 text-slate-300 border-slate-500/30",
};

const disasterIcon: Record<string, string> = {
  earthquake: "🌍", flood: "🌊", cyclone: "🌀", wildfire: "🔥", landslide: "⛰️",
};

function timeAgo(date: string | Date) {
  const seconds = Math.floor((Date.now() - new Date(date).getTime()) / 1000);
  if (seconds < 60) return `${seconds}s ago`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  return `${Math.floor(seconds / 3600)}h ago`;
}

type AnalysisResult = {
  severity: "low" | "moderate" | "severe";
  confidence: number;
  affectedArea: number;
  structuresAffected: number;
  processingTime: number;
  pointsProcessed: number;
  classificationBreakdown: { low: number; moderate: number; severe: number };
  location: string;
  disasterType: string;
};

export default function Assessment() {
  const { toast } = useToast();
  const qc = useQueryClient();
  const [filterSeverity, setFilterSeverity] = useState("all");
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [progress, setProgress] = useState(0);

  const [form, setForm] = useState({
    location: "",
    disasterType: "earthquake",
    latitude: "",
    longitude: "",
    pointCloudDensity: "45000",
  });

  const { data: assessments, isLoading } = useQuery<DamageAssessment[]>({
    queryKey: ["/api/assessments"],
  });

  const updateStatus = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      await apiRequest("PATCH", `/api/assessments/${id}/status`, { status });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["/api/assessments"] });
      qc.invalidateQueries({ queryKey: ["/api/stats"] });
      toast({ title: "Status updated successfully" });
    },
  });

  const runAnalysis = async () => {
    if (!form.location) {
      toast({ title: "Please enter a location", variant: "destructive" });
      return;
    }
    setAnalyzing(true);
    setProgress(0);
    setAnalysisResult(null);

    const steps = [
      { label: "Loading point cloud data", pct: 20 },
      { label: "Preprocessing & denoising", pct: 40 },
      { label: "Running CNN classification", pct: 65 },
      { label: "Severity segmentation", pct: 85 },
      { label: "Generating damage report", pct: 100 },
    ];

    for (const step of steps) {
      await new Promise((r) => setTimeout(r, 280));
      setProgress(step.pct);
    }

    try {
      const res = await apiRequest("POST", "/api/analyze", {
        location: form.location,
        disasterType: form.disasterType,
        pointCloudDensity: parseInt(form.pointCloudDensity),
      });
      const data = await res.json();
      setAnalysisResult(data);

      await apiRequest("POST", "/api/assessments", {
        location: form.location,
        latitude: parseFloat(form.latitude) || 18.5 + Math.random() * 0.1,
        longitude: parseFloat(form.longitude) || 73.8 + Math.random() * 0.1,
        severity: data.severity,
        confidence: data.confidence,
        disasterType: form.disasterType,
        pointCloudDensity: data.pointsProcessed,
        affectedArea: data.affectedArea,
        structuresAffected: data.structuresAffected,
        status: "active",
      });
      qc.invalidateQueries({ queryKey: ["/api/assessments"] });
      qc.invalidateQueries({ queryKey: ["/api/stats"] });
    } catch {
      toast({ title: "Analysis failed", variant: "destructive" });
    }
    setAnalyzing(false);
  };

  const filtered = assessments?.filter(
    (a) => filterSeverity === "all" || a.severity === filterSeverity
  ) ?? [];

  return (
    <div className="p-4 md:p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Damage Assessment</h1>
        <p className="text-slate-400 text-sm mt-1">AI-powered LiDAR point cloud analysis with CNN classification</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Analysis Form */}
        <Card className="bg-slate-800/50 border-slate-700">
          <CardHeader>
            <CardTitle className="text-sm font-semibold text-slate-200 flex items-center gap-2">
              <Cpu className="h-4 w-4 text-blue-400" />
              Run AI-LiDAR Analysis
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label className="text-xs text-slate-400">Location Name</Label>
              <Input
                placeholder="e.g. Parvati Valley, Pune"
                value={form.location}
                onChange={(e) => setForm({ ...form, location: e.target.value })}
                className="bg-slate-700 border-slate-600 text-white placeholder:text-slate-500"
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-2">
                <Label className="text-xs text-slate-400">Disaster Type</Label>
                <Select value={form.disasterType} onValueChange={(v) => setForm({ ...form, disasterType: v })}>
                  <SelectTrigger className="bg-slate-700 border-slate-600 text-white">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-slate-800 border-slate-600">
                    {["earthquake", "flood", "cyclone", "wildfire", "landslide"].map((t) => (
                      <SelectItem key={t} value={t} className="text-slate-200 capitalize">{t}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label className="text-xs text-slate-400">Point Cloud Density</Label>
                <Select value={form.pointCloudDensity} onValueChange={(v) => setForm({ ...form, pointCloudDensity: v })}>
                  <SelectTrigger className="bg-slate-700 border-slate-600 text-white">
                    <SelectValue />
