                          </div>
                          <p className="text-xs text-slate-300 mt-1 leading-relaxed">{alert.description}</p>
                        </div>
                        {!alert.acknowledged && (
                          <Button
                            size="sm"
                            variant="outline"
                            className="h-7 text-xs border-slate-500 text-slate-300 hover:bg-slate-700 flex-shrink-0"
