import { useEffect, useRef, useState } from "react";
import * as THREE from "three";

interface LidarPointCloudProps {
  severity?: "low" | "moderate" | "severe";
  isScanning?: boolean;
  onScanComplete?: () => void;
}

function generateDisasterPointCloud(severity: "low" | "moderate" | "severe"): Float32Array {
  const count = 12000;
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);

  const damageFactor = severity === "severe" ? 0.9 : severity === "moderate" ? 0.5 : 0.2;

  for (let i = 0; i < count; i++) {
    const angle = Math.random() * Math.PI * 2;
    const radius = Math.random() * 8;
    const x = Math.cos(angle) * radius;
    const z = Math.sin(angle) * radius;

    let y = 0;
    const dist = Math.sqrt(x * x + z * z);

    if (dist < 3) {
      // Building / structure
      y = 2 + Math.random() * 4;
      const dmg = Math.random() < damageFactor;
      if (dmg) {
        y *= (0.2 + Math.random() * 0.5); // collapsed
        colors[i * 3] = 0.9;
        colors[i * 3 + 1] = 0.2;
        colors[i * 3 + 2] = 0.2;
      } else {
        colors[i * 3] = 0.2;
        colors[i * 3 + 1] = 0.7;
        colors[i * 3 + 2] = 0.9;
      }
    } else if (dist < 5) {
      // Debris zone
      y = Math.random() * damageFactor * 2;
      const debris = Math.random() < damageFactor;
      if (debris) {
        colors[i * 3] = 0.8;
        colors[i * 3 + 1] = 0.5;
        colors[i * 3 + 2] = 0.1;
      } else {
        colors[i * 3] = 0.3;
        colors[i * 3 + 1] = 0.6;
        colors[i * 3 + 2] = 0.3;
      }
    } else {
      // Ground / terrain
      y = (Math.random() - 0.5) * 0.4;
      colors[i * 3] = 0.3;
      colors[i * 3 + 1] = 0.5;
      colors[i * 3 + 2] = 0.3;
    }

    // Noise
    positions[i * 3] = x + (Math.random() - 0.5) * 0.3;
    positions[i * 3 + 1] = y + (Math.random() - 0.5) * 0.1;
    positions[i * 3 + 2] = z + (Math.random() - 0.5) * 0.3;
  }

  return positions;
}

function generateColors(positions: Float32Array, severity: "low" | "moderate" | "severe"): Float32Array {
  const count = positions.length / 3;
  const colors = new Float32Array(count * 3);
  const damageFactor = severity === "severe" ? 0.9 : severity === "moderate" ? 0.5 : 0.2;

  for (let i = 0; i < count; i++) {
    const x = positions[i * 3];
    const y = positions[i * 3 + 1];
    const z = positions[i * 3 + 2];
    const dist = Math.sqrt(x * x + z * z);

    if (dist < 3 && y < 1.5 && Math.random() < damageFactor) {
      // Severe damage — red
      colors[i * 3] = 0.95;
      colors[i * 3 + 1] = 0.2 + Math.random() * 0.2;
      colors[i * 3 + 2] = 0.1;
    } else if (dist < 5 && y > 0.3 && Math.random() < damageFactor) {
      // Debris — orange
      colors[i * 3] = 0.9;
      colors[i * 3 + 1] = 0.5 + Math.random() * 0.3;
      colors[i * 3 + 2] = 0.05;
    } else if (y > 1.5) {
      // Intact structure — blue
      colors[i * 3] = 0.2;
      colors[i * 3 + 1] = 0.6;
      colors[i * 3 + 2] = 1.0;
    } else {
      // Ground — green
      colors[i * 3] = 0.2 + Math.random() * 0.1;
      colors[i * 3 + 1] = 0.55 + Math.random() * 0.2;
      colors[i * 3 + 2] = 0.2 + Math.random() * 0.1;
    }
  }
  return colors;
}

export default function LidarPointCloud({ severity = "moderate", isScanning = false, onScanComplete }: LidarPointCloudProps) {
  const mountRef = useRef<HTMLDivElement>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const pointsRef = useRef<THREE.Points | null>(null);
  const scanLineRef = useRef<THREE.Mesh | null>(null);
  const frameRef = useRef<number>(0);
  const scanAngleRef = useRef<number>(0);
  const revealedRef = useRef<number>(0);
  const [scanPct, setScanPct] = useState(0);

  useEffect(() => {
    if (!mountRef.current) return;

    const w = mountRef.current.clientWidth;
    const h = mountRef.current.clientHeight;

    // Scene
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0f1a);
    scene.fog = new THREE.FogExp2(0x0a0f1a, 0.04);
    sceneRef.current = scene;

    // Camera
    const camera = new THREE.PerspectiveCamera(60, w / h, 0.1, 100);
    camera.position.set(10, 8, 10);
    camera.lookAt(0, 1, 0);
    cameraRef.current = camera;

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    mountRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // Grid
    const gridHelper = new THREE.GridHelper(20, 20, 0x1a2a3a, 0x0d1a24);
    scene.add(gridHelper);

    // Scan origin marker
    const originGeo = new THREE.SphereGeometry(0.15, 8, 8);
    const originMat = new THREE.MeshBasicMaterial({ color: 0x00cfff });
    const origin = new THREE.Mesh(originGeo, originMat);
    origin.position.set(0, 6, 0);
    scene.add(origin);

    // Sensor beam lines (visual LiDAR beams)
    const beamGeo = new THREE.CylinderGeometry(0.01, 0.01, 6, 4);
    const beamMat = new THREE.MeshBasicMaterial({ color: 0x00cfff, transparent: true, opacity: 0.15 });
    for (let i = 0; i < 16; i++) {
      const angle = (i / 16) * Math.PI * 2;
      const beam = new THREE.Mesh(beamGeo, beamMat);
      beam.position.set(Math.cos(angle) * 1.5, 3, Math.sin(angle) * 1.5);
      beam.rotation.x = Math.PI / 4;
      beam.rotation.y = angle;
      scene.add(beam);
    }

    // Scan plane
    const scanGeo = new THREE.CylinderGeometry(9, 9, 0.05, 64, 1, true);
    const scanMat = new THREE.MeshBasicMaterial({
      color: 0x00cfff,
      transparent: true,
      opacity: 0.08,
      side: THREE.DoubleSide,
    });
    const scanLine = new THREE.Mesh(scanGeo, scanMat);
    scanLine.position.y = 0.1;
    scene.add(scanLine);
    scanLineRef.current = scanLine;

    // Point cloud
    const positions = generateDisasterPointCloud(severity);
    const colors = generateColors(positions, severity);
    const count = positions.length / 3;

    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    geo.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    // Start invisible
    const alphas = new Float32Array(count).fill(0);
    geo.setAttribute("alpha", new THREE.BufferAttribute(alphas, 1));

    const mat = new THREE.PointsMaterial({
      size: 0.12,
      vertexColors: true,
      transparent: true,
      opacity: 0.9,
      sizeAttenuation: true,
    });

    const points = new THREE.Points(geo, mat);
    scene.add(points);
    pointsRef.current = points;

    // Ambient light
    scene.add(new THREE.AmbientLight(0x112244, 2));

    // Mouse orbit
    let isDragging = false;
    let prevX = 0, prevY = 0;
    let rotX = 0.4, rotY = 0;

    const onMouseDown = (e: MouseEvent) => { isDragging = true; prevX = e.clientX; prevY = e.clientY; };
    const onMouseUp = () => { isDragging = false; };
    const onMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      rotY += (e.clientX - prevX) * 0.01;
      rotX += (e.clientY - prevY) * 0.005;
      rotX = Math.max(0.1, Math.min(1.2, rotX));
      prevX = e.clientX; prevY = e.clientY;
    };

    renderer.domElement.addEventListener("mousedown", onMouseDown);
    window.addEventListener("mouseup", onMouseUp);
    window.addEventListener("mousemove", onMouseMove);

    // Touch
    let lastTouchX = 0;
    const onTouchStart = (e: TouchEvent) => { lastTouchX = e.touches[0].clientX; };
    const onTouchMove = (e: TouchEvent) => { rotY += (e.touches[0].clientX - lastTouchX) * 0.01; lastTouchX = e.touches[0].clientX; };
    renderer.domElement.addEventListener("touchstart", onTouchStart);
    renderer.domElement.addEventListener("touchmove", onTouchMove);

    let scanStartTime = Date.now();
    const SCAN_DURATION = 4000;

    const animate = () => {
      frameRef.current = requestAnimationFrame(animate);

      const elapsed = Date.now() - scanStartTime;
      const pct = Math.min(elapsed / SCAN_DURATION, 1);

      // Rotate scan plane
      scanAngleRef.current += 0.04;
      if (scanLineRef.current) {
        scanLineRef.current.rotation.y = scanAngleRef.current;
      }

      // Reveal points progressively
      const geo = pointsRef.current?.geometry;
      if (geo && pct < 1) {
        const alphaAttr = geo.getAttribute("alpha") as THREE.BufferAttribute;
        const posAttr = geo.getAttribute("position") as THREE.BufferAttribute;
        const count = posAttr.count;
        const targetRevealed = Math.floor(pct * count);

        for (let i = revealedRef.current; i < targetRevealed; i++) {
          const px = posAttr.getX(i);
          const pz = posAttr.getZ(i);
          const ptAngle = Math.atan2(pz, px);
          const scanA = ((scanAngleRef.current % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
          const diff = Math.abs(ptAngle - (scanA - Math.PI));
          if (diff < 0.8 || diff > Math.PI * 2 - 0.8) {
            alphaAttr.setX(i, 1);
          }
        }
        revealedRef.current = targetRevealed;
        alphaAttr.needsUpdate = true;
        setScanPct(Math.round(pct * 100));
      }

      if (pct >= 1 && scanLineRef.current) {
        scanLineRef.current.material.opacity = Math.max(0, scanLineRef.current.material.opacity - 0.01);
        if (onScanComplete && revealedRef.current < (pointsRef.current?.geometry.getAttribute("position").count ?? 0)) {
          const alphaAttr = geo!.getAttribute("alpha") as THREE.BufferAttribute;
          for (let i = 0; i < alphaAttr.count; i++) alphaAttr.setX(i, 1);
          alphaAttr.needsUpdate = true;
          revealedRef.current = alphaAttr.count;
          onScanComplete();
        }
      }

      // Rotate camera
      if (!isDragging) rotY += 0.003;
      const r = 16;
      camera.position.x = Math.cos(rotY) * Math.cos(rotX) * r;
      camera.position.y = Math.sin(rotX) * r * 0.6 + 2;
      camera.position.z = Math.sin(rotY) * Math.cos(rotX) * r;
      camera.lookAt(0, 1, 0);

      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mountRef.current) return;
      const w = mountRef.current.clientWidth;
      const h = mountRef.current.clientHeight;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      cancelAnimationFrame(frameRef.current);
      renderer.domElement.removeEventListener("mousedown", onMouseDown);
      window.removeEventListener("mouseup", onMouseUp);
      window.removeEventListener("mousemove", onMouseMove);
      renderer.domElement.removeEventListener("touchstart", onTouchStart);
      renderer.domElement.removeEventListener("touchmove", onTouchMove);
      window.removeEventListener("resize", handleResize);
      renderer.dispose();
      if (mountRef.current && renderer.domElement.parentNode === mountRef.current) {
        mountRef.current.removeChild(renderer.domElement);
      }
    };
  }, [severity]);

  return (
    <div className="relative w-full h-full">
      <div ref={mountRef} className="w-full h-full cursor-grab active:cursor-grabbing" />
      {scanPct < 100 && (
        <div className="absolute bottom-3 left-3 right-3">
          <div className="flex items-center justify-between text-xs text-cyan-400 mb-1">
            <span className="font-mono">LiDAR SCAN PROGRESS</span>
            <span className="font-mono font-bold">{scanPct}%</span>
          </div>
          <div className="h-1 bg-slate-700 rounded-full overflow-hidden">
            <div
              className="h-full bg-cyan-400 rounded-full transition-all duration-100"
              style={{ width: `${scanPct}%` }}
            />
          </div>
        </div>
      )}
      <div className="absolute top-3 right-3 text-[10px] text-slate-500 font-mono">drag to rotate</div>
    </div>
  );
}

import { useState, useEffect, useRef } from "react";
import { CheckCircle2, Circle, Loader2, Wifi, WifiOff, Zap, Radio } from "lucide-react";
import { cn } from "@/lib/utils";

interface InitStep {
  id: string;
  label: string;
  detail: string;
  durationMs: number;
  status: "pending" | "running" | "done" | "error";
}

const INIT_STEPS: Omit<InitStep, "status">[] = [
  { id: "power", label: "Sensor Power-On", detail: "Velodyne VLP-32C · 12V DC · 10W", durationMs: 600 },
  { id: "motor", label: "Motor Spin-Up", detail: "Rotating mirror assembly · 10–20 Hz target", durationMs: 900 },
  { id: "laser", label: "Laser Array Init", detail: "32 laser emitters · 903 nm wavelength", durationMs: 500 },
  { id: "calibration", label: "Factory Calibration Load", detail: "Loading beam angle offsets & intensity corrections", durationMs: 700 },
  { id: "network", label: "UDP Network Bind", detail: "192.168.1.201:2368 · PCAP stream ready", durationMs: 400 },
  { id: "lidar_sync", label: "GPS Time Sync", detail: "PPS signal · NMEA timestamp alignment", durationMs: 800 },
  { id: "selftest", label: "Self-Test & Diagnostics", detail: "Internal temperature 28°C · Voltage nominal", durationMs: 600 },
  { id: "pointcloud", label: "Point Cloud Pipeline", detail: "Open3D preprocessing · voxel downsampling 0.05m", durationMs: 900 },
  { id: "cnn", label: "CNN Model Load", detail: "PointNet++ weights · 89% accuracy checkpoint", durationMs: 1100 },
  { id: "ready", label: "System Ready", detail: "AI-LiDAR framework operational · 360° scan active", durationMs: 300 },
];

interface Props {
  onComplete?: () => void;
  autoStart?: boolean;
}

const sensorParams = [
  { label: "Model", value: "Velodyne VLP-32C" },
  { label: "Channels", value: "32 beam" },
  { label: "Range", value: "200 m max" },
  { label: "Accuracy", value: "±3 cm" },
  { label: "Scan Rate", value: "10–20 Hz" },
  { label: "Points/sec", value: "600,000+" },
  { label: "FOV (H)", value: "360°" },
  { label: "FOV (V)", value: "−25° to +15°" },
  { label: "Wavelength", value: "903 nm" },
  { label: "IP Rating", value: "IP67" },
];

export default function LidarInitPanel({ onComplete, autoStart = false }: Props) {
  const [steps, setSteps] = useState<InitStep[]>(
    INIT_STEPS.map((s) => ({ ...s, status: "pending" }))
  );
  const [started, setStarted] = useState(autoStart);
  const [done, setDone] = useState(false);
  const [scanRate, setScanRate] = useState(0);
  const [pointsPerSec, setPointsPerSec] = useState(0);
  const [temp, setTemp] = useState(0);
  const tickRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (!started) return;

    let stepIdx = 0;

    const runNext = () => {
      if (stepIdx >= INIT_STEPS.length) {
        setDone(true);
        onComplete?.();
        return;
      }

      const currentIdx = stepIdx;
      setSteps((prev) =>
        prev.map((s, i) => (i === currentIdx ? { ...s, status: "running" } : s))
      );

      setTimeout(() => {
        setSteps((prev) =>
          prev.map((s, i) => (i === currentIdx ? { ...s, status: "done" } : s))
        );
        stepIdx++;
        setTimeout(runNext, 80);
      }, INIT_STEPS[currentIdx].durationMs);
    };

    runNext();
  }, [started]);

  // Animate live sensor readings once done
  useEffect(() => {
    if (!done) return;
    setScanRate(10);
    setPointsPerSec(0);
    setTemp(28);

    let t = 0;
    tickRef.current = setInterval(() => {
      t += 1;
      setScanRate(10 + Math.sin(t * 0.3) * 2);
      setPointsPerSec(580000 + Math.floor(Math.sin(t * 0.2) * 20000));
      setTemp(28 + Math.sin(t * 0.1) * 1.5);
    }, 200);

    return () => { if (tickRef.current) clearInterval(tickRef.current); };
  }, [done]);

  return (
    <div className="flex flex-col gap-4 h-full">
      {/* Sensor spec header */}
      <div className="flex items-center gap-3 p-3 rounded-lg bg-cyan-500/10 border border-cyan-500/20">
        <div className="relative flex-shrink-0">
          <Radio className={cn("h-7 w-7", done ? "text-cyan-400" : started ? "text-cyan-300 animate-pulse" : "text-slate-500")} />
          {done && (
            <span className="absolute -top-1 -right-1 w-3 h-3 bg-green-400 rounded-full border-2 border-slate-900" />
          )}
        </div>
        <div>
          <div className="text-sm font-bold text-slate-100">Velodyne VLP-32C LiDAR</div>
          <div className="text-xs text-slate-400 font-mono">SN: VLP32-20241108-07432</div>
        </div>
        <div className="ml-auto">
          {!started && (
            <button
              onClick={() => setStarted(true)}
              className="flex items-center gap-2 px-4 py-1.5 rounded-lg bg-cyan-600 hover:bg-cyan-500 text-white text-xs font-semibold transition-colors"
            >
              <Zap className="h-3.5 w-3.5" />
              Initialize
            </button>
          )}
          {started && !done && (
            <span className="flex items-center gap-1.5 text-xs text-cyan-400 font-mono">
              <Loader2 className="h-3.5 w-3.5 animate-spin" />
              Initializing...
            </span>
          )}
          {done && (
            <span className="flex items-center gap-1.5 text-xs text-green-400 font-mono font-bold">
              <CheckCircle2 className="h-3.5 w-3.5" />
              ONLINE
            </span>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 flex-1 min-h-0">
        {/* Init sequence log */}
        <div className="flex flex-col gap-1.5 overflow-y-auto pr-1">
          <div className="text-[10px] text-slate-500 font-mono uppercase tracking-wider mb-1">Init Sequence Log</div>
          {steps.map((step) => (
            <div
              key={step.id}
              className={cn(
                "flex items-start gap-2.5 p-2 rounded-lg transition-all duration-300",
                step.status === "done" && "bg-slate-800/40",
                step.status === "running" && "bg-cyan-500/10 border border-cyan-500/20",
                step.status === "pending" && "opacity-40"
              )}
            >
              <div className="flex-shrink-0 mt-0.5">
                {step.status === "done" && <CheckCircle2 className="h-3.5 w-3.5 text-green-400" />}
                {step.status === "running" && <Loader2 className="h-3.5 w-3.5 text-cyan-400 animate-spin" />}
                {step.status === "pending" && <Circle className="h-3.5 w-3.5 text-slate-600" />}
              </div>
              <div>
                <div className={cn(
                  "text-xs font-medium",
                  step.status === "done" ? "text-slate-300" :
                  step.status === "running" ? "text-cyan-300" : "text-slate-500"
                )}>{step.label}</div>
                <div className="text-[10px] text-slate-500 font-mono mt-0.5">{step.detail}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Right column: specs + live readings */}
        <div className="flex flex-col gap-3">
          {/* Sensor specs */}
          <div>
            <div className="text-[10px] text-slate-500 font-mono uppercase tracking-wider mb-2">Sensor Specifications</div>
            <div className="grid grid-cols-2 gap-1">
              {sensorParams.map(({ label, value }) => (
                <div key={label} className="flex flex-col p-1.5 rounded bg-slate-800/50">
                  <span className="text-[9px] text-slate-500 uppercase tracking-wider">{label}</span>
                  <span className="text-xs font-mono font-semibold text-slate-200">{value}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Live telemetry */}
          {done && (
            <div>
              <div className="text-[10px] text-slate-500 font-mono uppercase tracking-wider mb-2">Live Telemetry</div>
              <div className="space-y-2">
                <TelemetryBar label="Scan Rate" value={scanRate.toFixed(1)} unit="Hz" pct={(scanRate / 20) * 100} color="bg-cyan-500" />
                <TelemetryBar label="Points/sec" value={(pointsPerSec / 1000).toFixed(0) + "K"} unit="" pct={(pointsPerSec / 600000) * 100} color="bg-blue-500" />
                <TelemetryBar label="Temp" value={temp.toFixed(1)} unit="°C" pct={(temp / 70) * 100} color={temp > 50 ? "bg-red-500" : "bg-green-500"} />
                <div className="flex items-center gap-2 p-2 rounded-lg bg-slate-800/50">
                  <Wifi className="h-3.5 w-3.5 text-green-400" />
                  <span className="text-xs text-slate-300 font-mono">UDP · 192.168.1.201:2368</span>
                  <span className="ml-auto text-[10px] text-green-400 font-mono font-bold">LIVE</span>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function TelemetryBar({ label, value, unit, pct, color }: {
  label: string; value: string; unit: string; pct: number; color: string;
}) {
  return (
    <div className="p-2 rounded-lg bg-slate-800/50">
      <div className="flex items-center justify-between mb-1">
        <span className="text-[10px] text-slate-400 uppercase tracking-wider">{label}</span>
        <span className="text-xs font-mono font-bold text-slate-200">{value} {unit}</span>
      </div>
      <div className="h-1.5 bg-slate-700 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-300 ${color}`}
          style={{ width: `${Math.min(100, pct)}%` }}
        />
      </div>
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import LidarPointCloud from "@/components/lidar-point-cloud";
import LidarInitPanel from "@/components/lidar-init-panel";
import { Radio, Layers, ScanSearch, ChevronDown, Info } from "lucide-react";
import { cn } from "@/lib/utils";

const severityOptions = [
  { value: "low", label: "Low Damage", color: "bg-green-500/20 text-green-300 border-green-500/30", dot: "bg-green-500" },
  { value: "moderate", label: "Moderate Damage", color: "bg-amber-500/20 text-amber-300 border-amber-500/30", dot: "bg-amber-500" },
  { value: "severe", label: "Severe Damage", color: "bg-red-500/20 text-red-300 border-red-500/30", dot: "bg-red-500" },
] as const;

const pipelineStages = [
  { label: "LiDAR Acquisition", detail: "Raw 3D point cloud (.las/.ply)", icon: "📡", active: true },
  { label: "Preprocessing", detail: "Noise removal · Voxel downsampling · Normalization", icon: "⚙️", active: true },
  { label: "CNN Classification", detail: "PointNet++ deep learning model", icon: "🧠", active: true },
  { label: "Severity Mapping", detail: "Low / Moderate / Severe segmentation", icon: "🗺️", active: true },
  { label: "Decision Support", detail: "Priority zones · Rescue routing output", icon: "🚨", active: true },
];

const legendItems = [
  { color: "bg-blue-400", label: "Intact Structure", desc: "Undamaged building points" },
  { color: "bg-red-500", label: "Collapsed Zone", desc: "Severe structural failure" },
  { color: "bg-amber-400", label: "Debris Field", desc: "Scattered material / rubble" },
  { color: "bg-green-500", label: "Ground / Terrain", desc: "Road surface & open ground" },
];

export default function LidarPage() {
  const [severity, setSeverity] = useState<"low" | "moderate" | "severe">("moderate");
  const [initDone, setInitDone] = useState(false);
  const [scanDone, setScanDone] = useState(false);
  const [cloudKey, setCloudKey] = useState(0);
  const [showInfo, setShowInfo] = useState(false);

  const handleSeverityChange = (v: "low" | "moderate" | "severe") => {
    setSeverity(v);
    setScanDone(false);
    setCloudKey((k) => k + 1);
  };

  return (
    <div className="p-4 md:p-6 space-y-4">
      {/* Header */}
      <div className="flex items-start justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <Radio className="h-6 w-6 text-cyan-400" />
            LiDAR System Integration
          </h1>
          <p className="text-slate-400 text-sm mt-1">
            Sensor initialization · 3D point cloud acquisition · AI damage classification
          </p>
        </div>
        <div className="flex items-center gap-2">
          <div className={cn(
            "flex items-center gap-2 px-3 py-1.5 rounded-full border text-xs font-medium",
            initDone
              ? "bg-green-500/10 border-green-500/20 text-green-400"
              : "bg-slate-700 border-slate-600 text-slate-400"
          )}>
            <div className={cn("w-2 h-2 rounded-full", initDone ? "bg-green-400 animate-pulse" : "bg-slate-500")} />
            {initDone ? "Sensor Online" : "Sensor Offline"}
          </div>
          <button
            onClick={() => setShowInfo(!showInfo)}
            className="p-1.5 rounded-lg bg-slate-700 hover:bg-slate-600 transition-colors"
          >
            <Info className="h-4 w-4 text-slate-400" />
          </button>
        </div>
      </div>

      {/* Info banner */}
      {showInfo && (
        <Card className="bg-blue-900/20 border-blue-500/30">
          <CardContent className="p-4 text-xs text-blue-200/80 leading-relaxed">
            <strong className="text-blue-300">How it works:</strong> The Velodyne VLP-32C emits 32 laser beams in a 360° sweep, generating 600K+ 3D points/second.
            Raw point clouds are preprocessed (denoised, downsampled) then fed into a PointNet++ CNN trained on the paper's 10,000-sample dataset.
            The model classifies each point as low / moderate / severe damage — coloured red (collapsed), orange (debris), or blue (intact).
            Drag the 3D view to inspect from any angle.
          </CardContent>
        </Card>
      )}

      {/* Pipeline stages */}
      <div className="flex items-center gap-1 overflow-x-auto pb-1">
        {pipelineStages.map((stage, i) => (
          <div key={stage.label} className="flex items-center gap-1 flex-shrink-0">
            <div className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-slate-800/70 border border-slate-700 text-xs">
              <span>{stage.icon}</span>
              <span className="text-slate-300 font-medium hidden sm:block">{stage.label}</span>
            </div>
            {i < pipelineStages.length - 1 && (
              <ChevronDown className="h-3 w-3 text-slate-600 rotate-[-90deg] flex-shrink-0" />
            )}
          </div>
        ))}
      </div>

      {/* Main 2-column layout */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">

        {/* Sensor Init Panel */}
        <Card className="bg-slate-800/50 border-slate-700">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-semibold text-slate-200 flex items-center gap-2">
              <Radio className="h-4 w-4 text-cyan-400" />
              Sensor Initialization
              {initDone && (
                <Badge className="bg-green-500/20 text-green-300 border-green-500/30 text-[10px] ml-auto">
                  ● READY
                </Badge>
              )}
            </CardTitle>
          </CardHeader>
          <CardContent className="h-[480px] overflow-hidden">
            <LidarInitPanel onComplete={() => setInitDone(true)} />
          </CardContent>
        </Card>

        {/* 3D Point Cloud Viewer */}
        <Card className="bg-slate-800/50 border-slate-700">
          <CardHeader className="pb-2">
            <div className="flex items-center justify-between flex-wrap gap-2">
              <CardTitle className="text-sm font-semibold text-slate-200 flex items-center gap-2">
                <Layers className="h-4 w-4 text-purple-400" />
                3D Point Cloud Viewer
                {scanDone && (
                  <Badge className="bg-purple-500/20 text-purple-300 border-purple-500/30 text-[10px]">
                    CNN CLASSIFIED
                  </Badge>
                )}
              </CardTitle>
              {/* Severity selector */}
              <div className="flex gap-1.5">
                {severityOptions.map((opt) => (
                  <button
                    key={opt.value}
                    onClick={() => handleSeverityChange(opt.value)}
                    className={cn(
                      "flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border transition-colors",
                      severity === opt.value ? opt.color : "bg-slate-700 border-slate-600 text-slate-400 hover:bg-slate-600"
                    )}
                  >
                    <div className={cn("w-1.5 h-1.5 rounded-full", opt.dot)} />
                    <span className="hidden sm:block">{opt.label}</span>
                    <span className="sm:hidden capitalize">{opt.value}</span>
                  </button>
                ))}
              </div>
            </div>
          </CardHeader>
          <CardContent className="p-0">
            <div className="h-[480px] rounded-b-lg overflow-hidden">
              <LidarPointCloud
                key={cloudKey}
                severity={severity}
                onScanComplete={() => setScanDone(true)}
              />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Bottom row: legend + stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
        {/* Point cloud legend */}
        {legendItems.map(({ color, label, desc }) => (
          <div key={label} className="flex items-center gap-3 p-3 rounded-lg bg-slate-800/50 border border-slate-700">
            <div className={`w-3 h-3 rounded-full flex-shrink-0 ${color}`} />
            <div>
              <div className="text-xs font-semibold text-slate-200">{label}</div>
              <div className="text-[10px] text-slate-400">{desc}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Algorithm note */}
      <Card className="bg-slate-800/30 border-slate-700/50">
        <CardContent className="p-4">
          <div className="flex items-start gap-3">
            <ScanSearch className="h-5 w-5 text-slate-400 flex-shrink-0 mt-0.5" />
            <div className="space-y-2 text-xs text-slate-400 leading-relaxed">
              <p>
                <span className="text-slate-300 font-semibold">Preprocessing pipeline</span> — Raw LiDAR output is denoised using statistical outlier removal (Open3D), 
                voxel-downsampled to 0.05m resolution, and Z-normalised before CNN inference.
              </p>
              <p>
                <span className="text-slate-300 font-semibold">Deep learning model</span> — PointNet++ processes 3D point clouds directly, learning local geometric features 
                (cracks, displaced beams, rubble profiles) without converting to 2D images. Trained 50 epochs, Adam optimizer, lr=0.001, 
                70/30 stratified split across 10,000 samples.
              </p>
              <p>
                <span className="text-slate-300 font-semibold">Paper results</span> — 89% accuracy, 88% precision, 90% recall, 89 F1-score — outperforming satellite (71%) 
                and UAV camera (78%) baselines. Response time reduced to ~28ms vs 95ms UAV and 180ms satellite.
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

